const crypto = require('crypto');
function id(q) { return 'card-' + crypto.createHash('sha256').update(q.trim().toLowerCase()).digest('hex').slice(0,12); }
const cards = [];
function add(topicId, question, answer, explanation, difficulty, bloomLevel, tags) {
  cards.push({ id: id(question), question, answer, explanation, difficulty, bloomLevel, tags, topicId });
}

// PSYCHIATRY - psych-psychosis (15)
add('psych-psychosis','A 22-year-old man has 6 months of auditory hallucinations (voices commenting on his actions), persecutory delusions, disorganized speech, and social withdrawal. He has no substance use or medical cause. Diagnosis?','Schizophrenia (DSM-5: ≥2 characteristic symptoms for ≥1 month, with continuous disturbance for ≥6 months including prodrome); distinguish from schizophreniform (<6 months) and brief psychotic disorder (<1 month)','CANMAT Schizophrenia Guidelines: schizophrenia is a chronic disorder affecting 1% of the population. Early psychosis intervention (EPI) programs improve outcomes. Antipsychotic medication is the cornerstone of treatment. Psychosocial interventions (CBT, supported employment, family therapy) are essential adjuncts.',4,'analyze',['schizophrenia','psychosis','DSM-5 criteria','hallucinations','psychiatry']);
add('psych-psychosis','What are positive vs. negative symptoms of schizophrenia?','Positive (excess): hallucinations, delusions, disorganized speech/behavior, catatonia; Negative (deficit): avolition, alogia, anhedonia, affective flattening, asociality — negative symptoms respond less to antipsychotics and predict functional disability','CANMAT guidelines: negative symptoms are associated with poor functional outcome and quality of life. Antipsychotics primarily improve positive symptoms. Paliperidone, amisulpride, and clozapine have modest benefits for negative symptoms. Depression must be differentiated from negative symptoms.',2,'recall',['positive symptoms','negative symptoms','schizophrenia','antipsychotics','psychiatry']);
add('psych-psychosis','What is the first-line pharmacological treatment for a first episode of psychosis?','Second-generation antipsychotic (SGA) at the lowest effective dose: olanzapine, risperidone, quetiapine, aripiprazole — start low, go slow; avoid FGA (first-generation) as first-line due to EPS risk','CANMAT guidelines: SGAs are preferred for first episode psychosis (lower EPS/tardive dyskinesia risk). Clozapine is reserved for treatment-resistant schizophrenia (failed ≥2 adequate antipsychotic trials). Long-acting injectable (LAI) antipsychotics improve adherence — consider early.',3,'recall',['antipsychotics','first episode psychosis','SGA','olanzapine','psychiatry']);
add('psych-psychosis','What is clozapine and when is it indicated?','Clozapine: most effective antipsychotic; indicated for treatment-resistant schizophrenia (failed ≥2 antipsychotics including ≥1 SGA at adequate doses/duration); must monitor ANC (absolute neutrophil count) weekly x26 weeks due to agranulocytosis risk','CANMAT guidelines: clozapine is the only antipsychotic proven effective for treatment-resistant schizophrenia (30% of cases). Risk of agranulocytosis: 0.8% (fatal in 0.1%). Other serious side effects: seizures (dose-related), myocarditis, metabolic syndrome. REMS (Risk Evaluation and Mitigation Strategy) program required.',4,'apply',['clozapine','treatment-resistant schizophrenia','agranulocytosis','ANC monitoring','psychiatry']);
add('psych-psychosis','What are the extrapyramidal side effects (EPS) of antipsychotics and how are they treated?','Acute dystonia (hours-days): diphenhydramine or benztropine IM; Akathisia (inner restlessness): beta-blockers (propranolol), benzodiazepines; Parkinsonism: reduce dose or switch to SGA; Tardive dyskinesia (months-years): switch to clozapine, valbenazine','CANMAT guidelines: EPS are more common with FGAs (haloperidol) than SGAs. Tardive dyskinesia is the most serious irreversible EPS — characterized by repetitive involuntary movements (orofacial, limb). AIMS (Abnormal Involuntary Movement Scale) monitoring required.',3,'apply',['extrapyramidal side effects','EPS','dystonia','tardive dyskinesia','akathisia','psychiatry']);
add('psych-psychosis','What is neuroleptic malignant syndrome (NMS) and how is it treated?','NMS: rare, life-threatening reaction to antipsychotics — hyperthermia, severe muscle rigidity (lead pipe), autonomic instability (tachycardia, BP changes), altered consciousness; treat by stopping antipsychotic, cooling, IV dantrolene or bromocriptine, ICU supportive care','NMS occurs with FGAs > SGAs. Risk factors: rapid dose escalation, dehydration, agitation, high potency antipsychotics. Labs: elevated CK (>1000 IU/L), leukocytosis, elevated LFTs. Distinguished from serotonin syndrome: slower onset, more rigidity, no clonus. Do NOT restart antipsychotic for 2 weeks.',5,'analyze',['NMS','neuroleptic malignant syndrome','antipsychotic','hyperthermia','psychiatry']);
add('psych-psychosis','What metabolic monitoring is required for patients on second-generation antipsychotics?','Baseline and every 3 months: weight/BMI, waist circumference; fasting glucose, lipid panel at baseline and 3 months; BP, HbA1c annually — olanzapine, clozapine, quetiapine have highest metabolic risk','CANMAT guidelines: metabolic syndrome occurs in 40-50% of schizophrenia patients. SGAs (especially clozapine, olanzapine) cause weight gain, hyperglycemia, and dyslipidemia. Aripiprazole and ziprasidone have the lowest metabolic risk. Metformin effective for SGA-induced weight gain.',2,'recall',['metabolic monitoring','SGA','metabolic syndrome','antipsychotic side effects','psychiatry']);
add('psych-psychosis','What is schizoaffective disorder and how is it diagnosed?','Schizoaffective disorder: uninterrupted period of illness with both psychotic symptoms (hallucinations/delusions) AND a major mood episode (depressive or manic), with ≥2 weeks of psychosis WITHOUT prominent mood symptoms','Schizoaffective disorder sits between schizophrenia and bipolar disorder. Distinguished from bipolar with psychotic features: psychosis must occur independently of mood episodes. Treatment: antipsychotic + mood stabilizer (for bipolar type) or antipsychotic + antidepressant (depressive type).',4,'analyze',['schizoaffective disorder','psychosis','mood disorder','diagnosis','psychiatry']);
add('psych-psychosis','What is brief psychotic disorder and what is the key distinguishing feature from schizophrenia?','Brief psychotic disorder: sudden onset psychotic symptoms lasting ≥1 day but <1 month, with full return to premorbid functioning; often triggered by severe stressor','Brief psychotic disorder has excellent prognosis with full recovery. Distinguished from schizophrenia by duration (<1 month) and full recovery. Schizophreniform disorder: 1-6 months. Treatment: short-term low-dose antipsychotic, supportive therapy, address stressor.',2,'recall',['brief psychotic disorder','schizophrenia duration','prognosis','DSM-5','psychiatry']);
add('psych-psychosis','What psychosocial interventions are evidence-based for schizophrenia?','CBT for psychosis (CBTp), family-based therapy, supported employment (IPS model), cognitive remediation, social skills training, assertive community treatment (ACT)','CANMAT guidelines recommend multimodal treatment for schizophrenia — antipsychotics alone are insufficient. ACT (Assertive Community Treatment) reduces hospitalizations and homelessness. Supported employment (IPS) helps patients return to work. Family psychoeducation reduces relapse rates by 20-30%.',2,'recall',['psychosocial treatment','CBT for psychosis','ACT','supported employment','schizophrenia','psychiatry']);
add('psych-psychosis','A 30-year-old on haloperidol 10mg/day develops neck stiffening and oculogyric crisis 2 hours after a dose increase. What is the diagnosis and immediate treatment?','Acute dystonic reaction; IV or IM benztropine 2mg or diphenhydramine 50mg — relief within 15-20 minutes; switch to SGA or lower dose','Acute dystonia is more common with high-potency FGAs (haloperidol, trifluoperazine) and in young males. Laryngeal dystonia can cause airway compromise — emergency. Oculogyric crisis: involuntary eye deviation. Prophylactic benztropine may be given with first doses of high-potency antipsychotics.',3,'apply',['acute dystonia','oculogyric crisis','benztropine','haloperidol','psychiatry']);
add('psych-psychosis','What is the role of long-acting injectable (LAI) antipsychotics in schizophrenia?','LAI antipsychotics (aripiprazole, paliperidone, haloperidol decanoate given every 2-4 weeks) improve adherence, reduce relapse, and decrease hospitalizations — consider for any patient with adherence issues','CANMAT guidelines: LAI antipsychotics eliminate covert non-adherence. Non-adherence is the #1 predictor of relapse in schizophrenia. LAI should be offered as an option to all patients with schizophrenia, not just non-adherent ones. LAI may be preferable as first-line in high-relapse-risk patients.',3,'apply',['LAI antipsychotics','long-acting injectable','adherence','schizophrenia relapse','psychiatry']);
add('psych-psychosis','What is the difference between delusions and overvalued ideas?','Delusion: fixed false belief held with absolute certainty, not shared by cultural group, not amenable to reason; Overvalued idea: intense preoccupation that is understandable given history but abnormally dominant (borderline between delusion and OCD)','Delusions are classified by content (persecutory, referential, grandiose, erotomanic, somatic) and quality (bizarre or non-bizarre). Bizarre delusions (impossible given cultural context) are more specific to schizophrenia. Overvalued ideas are seen in OCD, anorexia, and body dysmorphic disorder.',3,'recall',['delusions','overvalued ideas','psychopathology','schizophrenia','psychiatry']);
add('psych-psychosis','What are the phases of schizophrenia and what is the prodrome?','Prodrome: 1-5 years before psychosis — social withdrawal, odd behavior, attenuated psychotic symptoms, decline in functioning; Acute phase: florid positive symptoms; Residual phase: negative symptoms and reduced positive symptoms','CANMAT Early Psychosis Guidelines: identifying the prodrome allows intervention before full psychosis. At-Risk Mental State (ARMS) clinics provide early intervention. Duration of Untreated Psychosis (DUP) correlates with worse outcomes — reduce DUP is a key public health goal.',3,'recall',['prodrome','early psychosis','schizophrenia phases','DUP','psychiatry']);
add('psych-psychosis','What is the management of acute agitation with psychosis in the ED?','De-escalation first; pharmacological: oral or IM haloperidol + lorazepam (combined most effective), or olanzapine IM (avoid with alcohol/benzodiazepines), or droperidol IM — monitor for EPS, respiratory depression','CPS/CANMAT emergency psychiatry guidelines: verbal de-escalation is the first approach for agitation. Parenteral antipsychotics for severe agitation. Olanzapine IM + parenteral benzodiazepine increases respiratory depression risk — do not combine. ECG monitoring for QTc prolongation with IV haloperidol.',4,'apply',['acute agitation','haloperidol','olanzapine IM','de-escalation','psychiatry']);

// PSYCHIATRY - psych-anxiety (15)
add('psych-anxiety','A 30-year-old has excessive worry about multiple life domains (work, family, health) that she cannot control, occurring more days than not for 8 months, with muscle tension, fatigue, and sleep difficulty. Diagnosis and first-line treatment?','Generalized Anxiety Disorder (GAD); first-line: SSRI (escitalopram, sertraline) or SNRI (venlafaxine, duloxetine) + CBT (cognitive restructuring, worry management)','CANMAT Anxiety Guidelines: CBT is the most effective psychotherapy for GAD. SSRIs/SNRIs take 4-8 weeks to work. Buspirone is an alternative non-benzodiazepine anxiolytic. Benzodiazepines: short-term only, risk of dependence. Pregabalin has evidence for GAD.',3,'apply',['GAD','generalized anxiety disorder','SSRI','CBT','CANMAT','psychiatry']);
add('psych-anxiety','What are the DSM-5 criteria for panic disorder?','Recurrent unexpected panic attacks (≥1 month of concern about future attacks OR behavioral change), at least 1 attack in past month; panic attack: abrupt surge of intense fear peaking within minutes with ≥4 symptoms (palpitations, dyspnea, chest pain, dizziness, paresthesias, depersonalization, fear of dying/going crazy)','CANMAT guidelines: panic disorder responds well to CBT (interoceptive exposure) and SSRIs. Breathing retraining and relaxation are adjuncts. Agoraphobia frequently complicates panic disorder. Benzodiazepines provide rapid relief but do not address underlying pathology and risk dependence.',3,'recall',['panic disorder','panic attack','DSM-5','CBT','psychiatry']);
add('psych-anxiety','What is the CANMAT recommended pharmacotherapy for panic disorder?','First-line: SSRIs (paroxetine, sertraline, escitalopram, citalopram) or SNRIs (venlafaxine); second-line: TCAs (imipramine, clomipramine); adjunct: benzodiazepines (short-term only) — avoid abrupt discontinuation','CANMAT panic disorder guidelines: start SSRI at low dose to avoid initial anxiogenic effect (jitteriness — worsen symptoms in first 1-2 weeks). Titrate slowly. Minimum 12 months of pharmacotherapy after remission. Propranolol is NOT effective for panic disorder (only for performance anxiety).',2,'recall',['panic disorder treatment','SSRI','paroxetine','CANMAT','psychiatry']);
add('psych-anxiety','A 25-year-old refuses to leave home alone, won\'t drive, and avoids shopping malls due to fear of having a panic attack in a place she can\'t escape. Diagnosis?','Agoraphobia; treat with exposure therapy (graduated real-life exposure is the most effective psychotherapy), SSRIs, or combined approach','Agoraphobia: fear of ≥2 situations (public transport, open spaces, enclosed spaces, crowds, outside alone) due to fear of escape being difficult or help unavailable if panic occurs. Comorbid with panic disorder in 50%. 40% of agoraphobia occurs without panic disorder.',3,'apply',['agoraphobia','exposure therapy','panic disorder','CBT','psychiatry']);
add('psych-anxiety','What is social anxiety disorder (social phobia) and how is it treated?','Marked fear of social situations where one may be scrutinized; first-line: CBT (exposure + cognitive restructuring) or SSRI/SNRI; performance-only subtype: propranolol or benzodiazepine PRN','CANMAT: paroxetine, sertraline, and venlafaxine have strongest evidence for SAD. CBT with exposures is highly effective. For performance anxiety: propranolol 10-40 mg PRN (30-60 min before performance). CBT + pharmacotherapy superior to either alone for severe SAD.',3,'apply',['social anxiety disorder','social phobia','CBT','SSRI','propranolol','psychiatry']);
add('psych-anxiety','What are the criteria for specific phobia and what is the most effective treatment?','Specific phobia: marked fear of specific object/situation (animals, blood-injection-injury, natural environment, situational) causing avoidance, >6 months, disproportionate to actual danger; treatment: exposure therapy (in vivo exposure)','CANMAT: exposure therapy is the gold standard for specific phobia (85% response rate). Imaginal exposure for phobias where in vivo is impractical. Blood-injection-injury phobia: applied tension technique (prevents vasovagal syncope). Medications generally not effective for specific phobia.',2,'recall',['specific phobia','exposure therapy','DSM-5','behavior therapy','psychiatry']);
add('psych-anxiety','What is PTSD and what are the DSM-5 criteria?','PTSD: exposure to trauma (death/threatened death, actual/threatened serious injury, sexual violence) → 4 symptom clusters: Intrusion (flashbacks, nightmares), Avoidance, Negative cognitions/mood, Hyperarousal — lasting >1 month','CANMAT PTSD Guidelines: 70% of Canadians will experience a traumatic event; PTSD develops in ~20%. Risk factors: severity of trauma, peritraumatic dissociation, prior trauma, lack of social support. First-line treatments: prolonged exposure therapy, EMDR, CPT (cognitive processing therapy), SSRIs/SNRIs.',3,'recall',['PTSD','post-traumatic stress disorder','DSM-5 criteria','trauma','psychiatry']);
add('psych-anxiety','What pharmacotherapy is recommended for PTSD?','SSRIs (sertraline, paroxetine — FDA-approved) and SNRIs (venlafaxine) are first-line; prazosin for PTSD nightmares; benzodiazepines are NOT recommended (no evidence, may worsen PTSD outcomes)','CANMAT PTSD guidelines: psychotherapy (PE, CPT, EMDR) is preferred over pharmacotherapy alone. Prazosin (alpha-1 blocker) reduces PTSD-associated nightmares and sleep disturbance. Benzodiazepines increase avoidance, impair fear extinction, and may worsen long-term outcomes.',3,'recall',['PTSD treatment','SSRI','prazosin','benzodiazepine contraindication','psychiatry']);
add('psych-anxiety','What is complex PTSD and how does it differ from PTSD?','Complex PTSD (ICD-11 but not DSM-5): PTSD symptoms + disturbances in self-organization: affect dysregulation, negative self-concept, interpersonal difficulties — results from prolonged, repeated trauma (childhood abuse, domestic violence, torture)','ICD-11 (used in Canada) includes complex PTSD as a separate diagnosis. CANMAT guidelines recognize that treatment is more challenging and requires longer duration. Stabilization phase before trauma processing is crucial. DBT and schema therapy useful for affect dysregulation.',4,'analyze',['complex PTSD','ICD-11','trauma','affect dysregulation','psychiatry']);
add('psych-anxiety','A 19-year-old has intrusive contamination obsessions and compulsive hand-washing for 3 hours daily causing significant distress. Diagnosis and first-line treatment?','OCD (Obsessive-Compulsive Disorder); first-line: CBT with exposure and response prevention (ERP) AND/OR SSRI (fluvoxamine, fluoxetine, sertraline, paroxetine, clomipramine)','CANMAT OCD guidelines: ERP (exposure to feared stimuli + preventing compulsive response) is the most effective psychotherapy for OCD. SSRIs at higher doses than depression (e.g., fluoxetine up to 80 mg). Clomipramine (TCA) most effective SSRI but poorest tolerability. Augmentation with atypical antipsychotics for partial response.',4,'apply',['OCD','obsessive-compulsive disorder','ERP','SSRI','CBT','psychiatry']);
add('psych-anxiety','What is the difference between OCD and OCD-related disorders?','OCD-related: Body dysmorphic disorder (preoccupation with perceived defect), hoarding disorder (inability to discard possessions), trichotillomania (hair pulling), excoriation (skin picking), illness anxiety disorder — all involve repetitive behaviors/thoughts','CANMAT/DSM-5: OCD spectrum disorders respond to SSRIs and habit-reversal training (trichotillomania, excoriation). BDD has overlap with social anxiety — treats with SSRI + CBT. Hoarding disorder: SSRI + specialized hoarding-specific CBT; traditional CBT less effective.',3,'recall',['OCD spectrum','body dysmorphic disorder','hoarding disorder','trichotillomania','psychiatry']);
add('psych-anxiety','What is the difference between adjustment disorder and acute stress reaction?','Acute stress reaction: immediate brief emotional/behavioral response within 3 days of trauma, resolving within 1 month; Adjustment disorder: emotional/behavioral symptoms within 3 months of identifiable stressor, disproportionate, lasting up to 6 months (12 months for chronic stressors)','Adjustment disorder: impairment must exceed expected reaction given the stressor. Does not meet criteria for other mental disorders. Treatment: supportive psychotherapy, brief CBT. Consider if full PTSD, MDD, or anxiety disorder diagnosis is more appropriate.',2,'recall',['adjustment disorder','acute stress reaction','DSM-5','stressor','psychiatry']);
add('psych-anxiety','What is health anxiety (illness anxiety disorder) and how is it managed?','Illness anxiety: preoccupation with having or acquiring a serious illness despite no/minimal medical symptoms; reassurance-seeking reinforces anxiety; treat with CBT (exposure + cognitive restructuring, stop reassurance-seeking) ± SSRI','Formerly somatic symptom disorder with poor illness anxiety (DSM-IV hypochondriasis). CBT targeting reassurance-seeking behaviors is most effective. Physicians should avoid extensive unnecessary testing. Regular brief scheduled appointments instead of symptom-driven visits reduce healthcare utilization.',3,'apply',['illness anxiety disorder','health anxiety','CBT','reassurance-seeking','psychiatry']);
add('psych-anxiety','What is separation anxiety disorder in adults and how does it present?','Separation anxiety disorder (SAD): excessive fear of separation from attachment figures (usually parents or partner); may persist from childhood or develop in adulthood; avoid separation situations, somatic complaints on separation','DSM-5 removed the "childhood onset" criterion — SAD can be diagnosed in adults. CANMAT: more common in women. Treat with CBT (exposure to separation) and SSRIs. Distinguish from agoraphobia (fear of panic situations, not specifically separation) and dependent personality disorder.',3,'apply',['separation anxiety disorder','adult SAD','CBT','SSRI','psychiatry']);
add('psych-anxiety','What is the response to benzodiazepines in anxiety treatment and what are the risks?','Rapid symptom relief (30-60 min) via GABA-A receptor enhancement; risks: tolerance, physical dependence (withdrawal seizures if abrupt discontinuation), cognitive impairment, falls in elderly, sedation, rebound anxiety','CANMAT guidelines: benzodiazepines are not recommended as long-term anxiolytic monotherapy. Short-term use (2-4 weeks) acceptable for acute anxiety. Taper gradually when discontinuing (10% dose reduction per week). Diazepam or clonazepam preferred for tapering due to longer half-life.',3,'apply',['benzodiazepines','anxiety treatment','dependence','withdrawal','CANMAT','psychiatry']);

// PSYCHIATRY - psych-substance (15)
add('psych-substance','A 45-year-old man is brought to the ED in acute alcohol withdrawal 24 hours after his last drink. He has tremors, diaphoresis, tachycardia, and is anxious. CIWA-Ar score is 18. What is the management?','Alcohol withdrawal: symptom-triggered benzodiazepine dosing using CIWA-Ar scale (lorazepam or diazepam); IV thiamine 100mg BEFORE glucose; monitor for delirium tremens and seizures','CCSMH (Canadian Coalition for Seniors Mental Health) and CAMH guidelines: IV/IM thiamine must be given BEFORE glucose to prevent Wernicke encephalopathy. Symptom-triggered benzodiazepine reduces medication use vs. fixed-dose schedule. Delirium tremens (Day 3-5): severe withdrawal with hyperthermia, hallucinations, autonomic instability.',4,'apply',['alcohol withdrawal','CIWA-Ar','benzodiazepine','thiamine','Wernicke','psychiatry']);
add('psych-substance','What medications are approved for alcohol use disorder (AUD) treatment in Canada?','Naltrexone (reduces craving, blocks opioid reward), acamprosate (reduces GABA/glutamate imbalance), disulfiram (aversive — acetaldehyde accumulation); extended-release naltrexone (Vivitrol) IM monthly','CANMAT/CAMH AUD guidelines: all three medications approved in Canada. Naltrexone preferred for heavy drinkers who want to reduce or abstain. Acamprosate for maintaining abstinence. Disulfiram requires high motivation (patient must consent to aversive reaction). Combine with behavioral therapy.',3,'recall',['alcohol use disorder','naltrexone','acamprosate','disulfiram','AUD treatment','psychiatry']);
add('psych-substance','What is opioid use disorder and what is the preferred treatment in Canada?','OUD: pattern of opioid use causing distress/impairment + ≥2 DSM-5 criteria; first-line treatment: buprenorphine-naloxone (Suboxone) or methadone — OAT (Opioid Agonist Therapy) reduces mortality 60-70%','CAMH and CCS (College of Family Physicians of Canada) guidelines: OAT is the gold standard for OUD. Buprenorphine-naloxone is preferred (lower overdose risk, office-based prescribing). Methadone requires monitored daily dosing at licensed pharmacy. Extended-release naltrexone (Vivitrol) as alternative.',3,'recall',['opioid use disorder','OAT','buprenorphine','methadone','naloxone','psychiatry']);
add('psych-substance','A patient is found unresponsive with pinpoint pupils, bradypnea (4 breaths/min), and is cyanotic. Suspected opioid overdose. What is the immediate management?','Naloxone (Narcan) 0.4-2 mg IV/IM/intranasal; support airway (BVM ventilation); repeat naloxone q2-3 min up to 10 mg if no response; titrate to adequate breathing (not full reversal to avoid withdrawal and re-narcotization)','CAMH naloxone guidelines: naloxone half-life (30-90 min) is shorter than most opioids — monitor for re-narcotization. Fentanyl overdose may require multiple higher doses (4-6 mg total). Take-home naloxone kits should be offered to all opioid users. Naloxone is available OTC in all Canadian provinces.',4,'apply',['opioid overdose','naloxone','Narcan','overdose reversal','psychiatry']);
add('psych-substance','What is the CAGE questionnaire and the AUDIT-C for alcohol screening?','CAGE: Cut down, Annoyed, Guilty, Eye-opener — ≥2 positive = probable AUD (sensitivity 71%, specificity 90%); AUDIT-C: first 3 questions of AUDIT — score ≥4 (men) or ≥3 (women) suggests harmful drinking','CAMH guidelines recommend AUDIT (Alcohol Use Disorders Identification Test) as standard screening tool in primary care. AUDIT-C is a brief validated screen. CAGE is simpler but less sensitive for detecting hazardous drinking (only detects dependence). Use in combination with clinical interview.',2,'recall',['CAGE questionnaire','AUDIT','alcohol screening','AUD','psychiatry']);
add('psych-substance','What is the delirium tremens (DT) and what are the risk factors and management?','DT: severe alcohol withdrawal (Day 3-5): altered consciousness, vivid hallucinations (tactile, visual), autonomic instability (hyperthermia, tachycardia, hypertension), seizures — 5-15% mortality if untreated','Risk factors for DT: prior DT, high CIWA-Ar, long duration of heavy drinking, BAL >300 mg/dL, acute medical illness, older age. Management: ICU admission, high-dose IV benzodiazepines (lorazepam or diazepam), phenobarbital for refractory cases, supportive care, treat precipitants.',5,'analyze',['delirium tremens','alcohol withdrawal','DT','benzodiazepines','ICU','psychiatry']);
add('psych-substance','What is cannabis use disorder and what are the health risks of chronic cannabis use?','Cannabis use disorder: ≥2 DSM-5 criteria from 11; health risks: CUD, cannabis hyperemesis syndrome, increased psychosis risk (2x in heavy users, especially with high-THC products), cognitive impairment (especially with adolescent onset), bronchitis','CANMAT and CAMH: no approved pharmacotherapy for cannabis use disorder. CBT and motivational enhancement therapy are evidence-based. Cannabis hyperemesis syndrome: recurrent vomiting, paradoxically relieved by hot showers — treat with haloperidol, capsaicin cream, and cessation of cannabis.',3,'recall',['cannabis use disorder','CUD','cannabis hyperemesis','psychosis risk','psychiatry']);
add('psych-substance','What is the management of stimulant (cocaine, methamphetamine) intoxication?','Cocaine intoxication: benzodiazepines for agitation/seizures, supportive care; avoid beta-blockers (unopposed alpha stimulation); CCBs or nitrates for coronary vasospasm; methamphetamine: similar management + treat hyperthermia aggressively','CAMH guidelines: cocaine overdose has no antidote. Cardiac complications (MI, VF) require standard ACS management — avoid beta-blockers. Hyperthermia from methamphetamine is life-threatening — active cooling with misting fans + benzodiazepines. Haloperidol for psychosis.',4,'apply',['cocaine intoxication','methamphetamine','stimulant overdose','benzodiazepines','psychiatry']);
add('psych-substance','What screening tools are available for substance use in primary care?','AUDIT (alcohol), ASSIST (Alcohol, Smoking and Substance Involvement Screening Test — multiple substances), DAST-10 (Drug Abuse Screening Test), CAGE-AID (adapted for drugs)','CANMAT guidelines recommend brief intervention after positive substance screening. 5-minute brief motivational interview at primary care level can reduce alcohol consumption. SBIRT (Screening, Brief Intervention, and Referral to Treatment) model is evidence-based.',2,'recall',['AUDIT','ASSIST','DAST','substance screening','psychiatry']);
add('psych-substance','What are the principles of harm reduction in substance use?','Harm reduction: reducing health, social, and economic harms without requiring abstinence; includes needle exchange programs, naloxone distribution, supervised consumption sites, drug checking services, OAT without abstinence requirements','CAMH/PHAC guidelines support harm reduction as an evidence-based approach to SUD. Supervised consumption sites (SCS) in Canada reduce overdose deaths, infections (HIV, hepatitis C), and emergency department visits without increasing community drug use. OAT is the highest-impact harm reduction intervention.',3,'recall',['harm reduction','supervised consumption','needle exchange','naloxone distribution','psychiatry']);
add('psych-substance','What is Wernicke-Korsakoff syndrome and how is it prevented?','Wernicke: acute thiamine (vitamin B1) deficiency — confusion, ataxia, ophthalmoplegia; Korsakoff: chronic amnestic syndrome from thiamine deficiency — anterograde amnesia, confabulation; prevent with IV thiamine before glucose in all alcohol-related presentations','Wernicke encephalopathy is reversible with IV thiamine — treatment must be given BEFORE glucose (glucose depletes thiamine). Korsakoff syndrome: 80% permanent amnesia. IV thiamine dose: 200-500 mg TID for 3-5 days (high doses needed for bioavailability). Give to all alcohol-related ED presentations.',4,'apply',['Wernicke-Korsakoff','thiamine deficiency','alcohol','confabulation','psychiatry']);
add('psych-substance','What is tobacco use disorder and what are the most effective cessation treatments?','Most effective: varenicline (Champix) — nicotinic receptor partial agonist (NRT 2.3x placebo, most effective individual treatment); combination NRT (patch + short-acting); bupropion; counseling enhances all pharmacotherapies','CANMAT/CAMH tobacco guidelines: varenicline doubles quit rates compared to NRT alone. Start 1 week before quit date. Side effects: nausea, vivid dreams, rare psychiatric effects (screen carefully). Combination NRT (patch + gum/lozenge) is more effective than patch alone.',3,'recall',['tobacco cessation','varenicline','NRT','nicotine replacement','psychiatry']);
add('psych-substance','What is the treatment for benzodiazepine dependence?','Gradual taper (10% dose reduction per week or per month for long-term users) using equivalent long-acting benzodiazepine (diazepam); CBT and psychoeducation; do NOT abruptly stop (seizure risk); avoid switching to another benzodiazepine','CANMAT guidelines: benzodiazepine withdrawal can be life-threatening (seizures). Convert to equivalent diazepam dose and taper over months. Carbamazepine or valproate may help. Gabapentin as adjunct for protracted withdrawal symptoms. Prevent new long-term benzodiazepine prescribing.',4,'apply',['benzodiazepine dependence','withdrawal','taper','diazepam','psychiatry']);
add('psych-substance','A 35-year-old heroin user is starting buprenorphine-naloxone (Suboxone). When should the first dose be given?','Give first dose when COWS score ≥8 (Clinical Opiate Withdrawal Scale — moderate withdrawal) or 12-24 hours after last short-acting opioid, 24-72 hours after last long-acting opioid','CAMH/CPSO guidelines: buprenorphine must be given when patient is in moderate withdrawal to prevent precipitated withdrawal (buprenorphine displaces full agonists from receptors, precipitating acute withdrawal if given too early). Low-dose induction (microdosing/Bernese protocol) for patients on high-dose fentanyl.',4,'apply',['buprenorphine induction','COWS','Suboxone','OAT','opioid withdrawal','psychiatry']);
add('psych-substance','What are the CANMAT low-risk alcohol use guidelines (LRDG)?','Low-risk drinking: ≤2 standard drinks/day (≤10/week for women, ≤15/week for men), with ≤3 per occasion — updated 2023 Canada guidance: >2 drinks/week = moderate risk, >6/week = high risk','CAMH/CCSA 2023 Canadian alcohol guidance: new evidence shows even low levels of alcohol increase cancer risk (breast, colorectal, liver). No safe level for cancer. Revised thresholds: 0-2 drinks/week = low risk; 3-6/week = moderate risk; 7+/week = high risk.',2,'recall',['low-risk alcohol','LRDG','CCSA','Canadian alcohol guidelines','psychiatry']);

// PSYCHIATRY - psych-suicide (15)
add('psych-suicide','A 45-year-old man expresses a wish to die. What are the key elements of suicide risk assessment?','SADPERSONS or Columbia Suicide Severity Rating Scale (C-SSRS): assess ideation (passive/active/plan/intent/means), history of attempts, protective factors, psychiatric diagnosis, social support, current stressors, access to means (especially firearms, medications)','CANMAT and CPA (Canadian Psychiatric Association) guidelines: all suicidal patients require structured risk assessment. High-risk features: plan + intent + means, prior attempt, male sex, older age, hopelessness, access to lethal means. Risk assessment guides level of care: safety planning, voluntary/involuntary hospitalization.',4,'apply',['suicide risk assessment','C-SSRS','Columbia scale','SADPERSONS','psychiatry']);
add('psych-suicide','What are the key epidemiological facts about suicide in Canada?','~4500 suicide deaths annually (Canada); highest rates in men 45-65 and Indigenous Canadians; men 3x more likely to die by suicide; women 3x more likely to attempt; firearms are the most lethal method (85% case fatality)','PHAC (Public Health Agency of Canada) suicide statistics: suicide is the 2nd leading cause of death for ages 15-34. Indigenous Canadians have 2-3x higher rates. Means restriction (reducing access to firearms and medications) is one of the most evidence-based suicide prevention strategies.',2,'recall',['suicide epidemiology','Canada','risk factors','means restriction','psychiatry']);
add('psych-suicide','What is the difference between suicidal ideation, intent, and plan?','Ideation: thoughts of death or self-harm; Intent: decision/resolution to act on ideation; Plan: specific method, time, and place identified — all three together = highest risk (requires immediate intervention and likely hospitalization)','C-SSRS distinguishes passive ideation ("I wish I were dead"), active ideation without plan, active with plan but no intent, active with intent and plan. Risk level guides intervention intensity. Safety planning and means restriction are key interventions before hospitalization.',3,'recall',['suicidal ideation','intent','plan','risk assessment','psychiatry']);
add('psych-suicide','What is a safety plan and how does it differ from a no-harm contract?','Safety plan: personalized crisis management plan — warning signs, coping strategies, social contacts, professional resources, means restriction; Evidence-based. No-harm contract: "I will not hurt myself" promise — NOT evidence-based and may provide false reassurance','CANMAT guidelines: safety planning (Stanley-Brown Safety Planning Intervention) is evidence-based and superior to no-harm contracts. Key elements: warning signs, internal coping strategies, social distractors, social supports to contact, crisis resources (distress lines), means restriction.',3,'apply',['safety planning','no-harm contract','suicide prevention','crisis plan','psychiatry']);
add('psych-suicide','Under what circumstances can a physician involuntarily admit a patient with suicidal ideation in Canada?','When patient has a mental disorder (not just suicidal ideation alone in some provinces), poses serious risk of physical harm to self or others, AND requires hospitalization for treatment — governed by provincial Mental Health Acts (e.g., Form 1 in Ontario, Form H1 in BC)','Each province has its own Mental Health Act for involuntary psychiatric admission. In Ontario, Form 1 (72h detention) can be completed by any physician who has examined the patient. Criteria must be met: serious mental disorder + imminent serious harm to self/others + needs hospitalization.',4,'apply',['involuntary admission','Mental Health Act','Form 1','Ontario','psychiatry']);
add('psych-suicide','What are the modifiable risk factors for suicide that should be targeted in treatment?','Hopelessness (strongest predictor), depression severity, untreated pain, access to lethal means (especially firearms), social isolation, substance use, poor treatment adherence — all are modifiable','CANMAT suicide prevention guidelines: reducing hopelessness is the strongest therapeutic target. Treating the underlying mental illness is essential. Means restriction: discuss safe storage of firearms and medications with family. Suicide-specific interventions: CBT-SP (CBT for suicide prevention), DBT, CAMS (Collaborative Assessment and Management of Suicidality).',3,'recall',['suicide risk factors','hopelessness','means restriction','suicide prevention','psychiatry']);
add('psych-suicide','What are the protective factors that reduce suicide risk?','Social support (family, community), reasons for living (children, religious beliefs, pets), engaged in mental health treatment, problem-solving skills, positive therapeutic alliance, cultural/spiritual beliefs that discourage suicide','CANMAT guidelines: protective factors help balance risk assessment and guide individualized safety planning. Connectedness to family and community is a strong protective factor — especially in First Nations communities where community-based prevention programs are effective. Hope is a key therapeutic target.',2,'recall',['protective factors','suicide prevention','resilience','reasons for living','psychiatry']);
add('psych-suicide','A 70-year-old man lost his wife 3 months ago and now expresses passive death wish. He drinks heavily and has given away his possessions. What is his risk level and management?','High risk — multiple risk factors: older male, recent loss, alcohol use, passive death wish, giving away possessions (preparatory behaviors); requires urgent psychiatric assessment and likely hospitalization','Giving away possessions and saying goodbyes are preparatory behaviors indicating high near-term risk. Older men are a high-risk group — often present to GPs rather than psychiatrists. Alcohol use markedly increases immediate suicide risk. CANMAT guidelines recommend hospitalization for high-risk patients.',5,'analyze',['suicide risk','elderly','bereavement','alcohol','high risk','psychiatry']);
add('psych-suicide','What is the evidence for lithium in suicide prevention?','Lithium reduces suicide and suicidal behavior by 60-80% in bipolar disorder and recurrent unipolar depression — the strongest anti-suicidal pharmacological agent; mechanism includes serotonergic effects and may reduce impulsivity','CANMAT Bipolar Guidelines: lithium is the only pharmacological agent with proven anti-suicidal properties. This is not true of valproate or other mood stabilizers. When starting lithium for bipolar disorder, the anti-suicidal benefit should be explicitly discussed with the patient.',3,'recall',['lithium','anti-suicidal','bipolar disorder','suicide prevention','psychiatry']);
add('psych-suicide','What is the Columbia Suicide Severity Rating Scale (C-SSRS) and how is it used clinically?','C-SSRS: 2 categories — ideation severity (passive wish to be dead, active ideation, ideation with plan, ideation with intent) and behavior (preparatory acts, interrupted attempt, aborted attempt, actual attempt) — standardized risk assessment tool','CANMAT recommends C-SSRS as the standard clinical suicide risk assessment tool. C-SSRS has been validated in emergency departments, inpatient, and outpatient settings. Identifies individuals at risk more reliably than clinical interview alone. Free online training available.',2,'recall',['C-SSRS','Columbia scale','suicide assessment','risk stratification','psychiatry']);
add('psych-suicide','What is postvention and why is it important?','Postvention: support provided to survivors (family, friends, colleagues) after a suicide death — reduces grief complications, survivor guilt, and secondary PTSD; also involves connecting to resources and reducing suicide contagion','CANMAT/CAMH: suicide survivors have 3x higher risk of dying by suicide. Postvention programs for schools, workplaces, and communities are evidence-based. Media guidelines (Reporting on Suicide): avoid detailed method descriptions, romanticization, and sensationalism — reduce contagion effect.',3,'recall',['postvention','suicide survivors','contagion','media guidelines','psychiatry']);
add('psych-suicide','What is passive suicidal ideation and how does it differ from active suicidal ideation?','Passive: wishes to be dead or "not wake up" — "I wish I were dead" without intent to act; Active: actual thoughts of killing oneself, with or without specific plan or intent','Clinical assessment of passive vs. active ideation guides management. Passive ideation may escalate to active ideation — requires monitoring and treatment of underlying disorder. Both require empathic inquiry without minimization. Passive ideation alone does not typically warrant involuntary hospitalization if protective factors are strong.',2,'recall',['passive suicidal ideation','active suicidal ideation','risk assessment','C-SSRS','psychiatry']);
add('psych-suicide','How should suicide risk be documented in the medical record?','Document: specific ideation content, presence/absence of plan and intent, means identified, history of attempts, protective factors, risk level assessment, clinical reasoning for management decision, plan and follow-up — comprehensive documentation supports continuity of care and medicolegal protection','CMPA (Canadian Medical Protective Association) guidelines: complete documentation of suicide risk assessment and rationale for management decisions is a medicolegal requirement. Include that means restriction was addressed. Document collateral information sources. Document capacity assessment if involuntary admission considered.',3,'apply',['documentation','suicide risk','medicolegal','capacity','psychiatry']);
add('psych-suicide','What are the evidence-based psychotherapies for suicidal patients?','CBT for suicide prevention (CBT-SP), Dialectical Behavior Therapy (DBT) — especially for BPD, Collaborative Assessment and Management of Suicidality (CAMS), Brief Cognitive Behavioral Therapy (BCBT-MIL)','CANMAT: DBT (Marsha Linehan) is the gold standard for BPD with suicidal behavior — reduces attempts by 50%. CAMS is a therapeutic framework for collaborative suicide risk assessment and management. CBT-SP reduces attempts in adolescents. All approaches involve hope installation and reasons for living.',3,'recall',['CBT-SP','DBT','CAMS','suicide psychotherapy','psychiatry']);
add('psych-suicide','What is physician-assisted dying (MAID) and how does it differ from suicide?','MAID (Medical Assistance in Dying): legal in Canada, for adults with a serious irremediable medical condition causing intolerable suffering — patient-requested, physician-administered or patient self-administered; NOT the same as suicide','Bill C-14 (2016) and C-7 (2021) legalized and expanded MAID in Canada. Eligibility: ≥18 years, serious irremediable illness, grievous/intolerable suffering (physical or psychological), capable of informed consent. Mental illness as sole underlying condition: planned eligibility from 2024. CANMAT provides guidance on mental health MAID requests.',4,'analyze',['MAID','medical assistance in dying','Canada','Bill C-7','psychiatry']);

// EMERGENCY MEDICINE - em-resus (20)
add('em-resus','A 55-year-old collapses in the ED. He is pulseless with VF on monitor. What are the immediate steps?','Immediately: start CPR (30:2), defibrillate (200J biphasic) as soon as defibrillator available, call for help; continue CPR 2 min, then rhythm check — ACLS algorithm','AHA/ACLS guidelines (adopted by Canadian emergency medicine): high-quality CPR is the most important intervention. Minimize interruptions (<10 seconds). Defibrillation within 2 minutes for shockable rhythms (VF/pVT). After shock: immediately resume CPR for 2 min before rhythm check.',5,'analyze',['cardiac arrest','VF','defibrillation','CPR','emergency medicine']);
add('em-resus','What is the ACLS algorithm for VF/pulseless VT?','Defibrillate → CPR 2 min → rhythm check → if shockable: defibrillate → CPR 2 min → IV/IO epinephrine 1mg q3-5 min → after 3rd shock: amiodarone 300mg IV → continue cycle','ACLS 2020: epinephrine should be given as soon as IV/IO access is established (after 1st shock if available, or during CPR cycles). Amiodarone 300 mg after 3rd shock (second dose 150 mg), or lidocaine as alternative. Avoid prolonged interruptions.',3,'recall',['VF','pulseless VT','ACLS','amiodarone','epinephrine','emergency medicine']);
add('em-resus','What is the ACLS algorithm for PEA (pulseless electrical activity) and asystole?','CPR + IV epinephrine 1mg q3-5 min (no shock — non-shockable); search for and treat reversible causes (5Hs + 5Ts)','5Hs: Hypovolemia, Hypoxia, Hydrogen ions (acidosis), Hypo/hyperkalemia, Hypothermia; 5Ts: Tamponade, Tension pneumothorax, Thrombosis (PE or MI), Toxins, Trauma — identification and treatment of reversible causes is the key to ROSC in PEA/asystole.',3,'recall',['PEA','asystole','ACLS','5H5T','reversible causes','emergency medicine']);
add('em-resus','What are the components of high-quality CPR?','Rate 100-120/min, depth 5-6 cm (adults), full chest recoil between compressions, minimize interruptions (<10 sec), avoid hyperventilation (10 breaths/min with advanced airway), rotate compressors every 2 min to prevent fatigue','ACLS 2020 guidelines: compression fraction >60% (time chest compressed during CPR). Avoid pausing CPR for rhythm check beyond 10 seconds. Switch compressors every 2 minutes. Continuous waveform capnography: ETCO2 <10 mmHg indicates poor CPR quality.',2,'recall',['high-quality CPR','chest compressions','ACLS guidelines','compression depth','emergency medicine']);
add('em-resus','What is ETCO2 monitoring and how is it used during cardiac arrest?','End-tidal CO2 (ETCO2): measures exhaled CO2; during CPR reflects cardiac output; ETCO2 <10 mmHg = poor CPR quality; ETCO2 sudden spike to >40 mmHg = ROSC; persistent ETCO2 <10 mmHg after 20 min = poor prognosis','ACLS 2020: continuous ETCO2 monitoring recommended during CPR. Used to assess CPR quality, confirm ET tube placement, and identify ROSC. ETCO2 can guide the decision to terminate resuscitation (controversial — other factors must be considered).',3,'apply',['ETCO2','capnography','cardiac arrest monitoring','ROSC','emergency medicine']);
add('em-resus','A patient achieves ROSC after cardiac arrest. What is the immediate post-resuscitation care?','Post-cardiac arrest care: targeted temperature management (TTM) 33-36°C for 24h if unconscious, hemodynamic optimization (MAP ≥65 mmHg), avoid hypoxia (SpO2 94-98%) and hypercapnia (PaCO2 35-45), ECG for STEMI, brain CT, urgent coronary angiography if cardiac cause suspected','TTM/hypothermia reduces neurological injury. ACLS 2020: TTM is recommended for unconscious post-arrest patients with shockable rhythm; reasonable for non-shockable. Avoid fever (>37.5°C) in all post-arrest patients. Emergent coronary angiography for ST elevation or suspected cardiac cause.',4,'apply',['post-cardiac arrest','targeted temperature management','TTM','ROSC care','emergency medicine']);
add('em-resus','What is the pediatric BLS sequence for a child (1-8 years)?','Single rescuer: C-A-B; 30:2 compressions-to-breaths (2-hand or 2-finger for infant), defibrillate (2 J/kg initial dose) for shockable rhythms — two rescuers: 15:2 ratio','Pediatric cardiac arrest is usually respiratory in origin (not cardiac). Airway management and ventilation are more critical than in adults. Epinephrine 0.01 mg/kg IV/IO (max 1mg). Shockable rhythms (VF/pVT) are less common in children. Amiodarone 5 mg/kg IV/IO.',3,'recall',['pediatric BLS','pediatric CPR','child cardiac arrest','30:2','emergency medicine']);
add('em-resus','What is the recommended approach to airway management in cardiac arrest?','Bag-valve-mask (BVM) ventilation preferred initially; advanced airway (ET tube or supraglottic) only when provider can place without interrupting CPR; after advanced airway: 10 breaths/min asynchronous with compressions','ACLS 2020: BVM ventilation by experienced rescuers may be as effective as ETI with less interruption. Video laryngoscopy preferred for ETI. Confirm ETI with ETCO2 and clinical assessment. Supraglottic airways (LMA, King LT) are alternatives to ETI.',2,'recall',['airway management','cardiac arrest','BVM','endotracheal intubation','emergency medicine']);
add('em-resus','When should cardiac resuscitation efforts be terminated?','Termination of resuscitation (TOR) in pre-hospital VF: unwitnessed + no bystander CPR + no ROSC after 3 cycles of ACLS and transport time >30 min — Bystanderr CPR rule: transport if ROSC, shockable rhythm, or bystander CPR initiated','Pre-hospital TOR rules (Canadian): BLS TOR rule: arrest not witnessed by EMS, no bystander CPR, no AED use before EMS, no ROSC after 3 ACLS cycles — consider field termination (high specificity for no survival). Exceptions: hypothermia, drowning, pregnancy, children.',4,'analyze',['termination of resuscitation','TOR','pre-hospital cardiac arrest','BLS','emergency medicine']);
add('em-resus','What are the shockable vs. non-shockable rhythms in cardiac arrest?','Shockable: Ventricular Fibrillation (VF) and Pulseless Ventricular Tachycardia (pVT) — defibrillate; Non-shockable: Pulseless Electrical Activity (PEA) and Asystole — NO defibrillation, focus on CPR and reversible causes','Defibrillation only works for VF/pVT by synchronously depolarizing myocardium. Attempting to defibrillate asystole or PEA is futile and wastes time. VF should be detected and defibrillated within 2 minutes — each minute of VF without defibrillation reduces survival by 10%.',2,'recall',['shockable rhythms','VF','PEA','asystole','defibrillation','emergency medicine']);
add('em-resus','What is therapeutic hypothermia (targeted temperature management) and who qualifies?','TTM 33-36°C for 24 hours: all adult patients who remain comatose after ROSC from cardiac arrest; evidence strongest for VF/pVT rhythms; also reasonable for non-shockable rhythms','TTM works by reducing cerebral metabolic rate (6-10% per degree decrease), reducing excitotoxicity and free radical production. Complications: bradycardia (expected), coagulopathy, electrolyte shifts, infection. Active fever prevention (normothermia 37°C) for all post-arrest patients not undergoing TTM.',3,'apply',['TTM','targeted temperature management','therapeutic hypothermia','post-cardiac arrest','emergency medicine']);
add('em-resus','What is the management of bradycardia with hemodynamic instability?','Atropine 0.5 mg IV q3-5 min (max 3 mg total); if no response: transcutaneous pacing immediately, then dopamine 2-10 mcg/kg/min or epinephrine 2-10 mcg/min IV infusion — identify and treat underlying cause','ACLS bradycardia algorithm: atropine first if hemodynamically unstable. Atropine may be ineffective for high-degree AV block (infranodal) or post-cardiac transplant — use transcutaneous pacing immediately for these. Transvenous pacing for definitive management while awaiting permanent pacemaker.',3,'apply',['bradycardia ACLS','atropine','transcutaneous pacing','hemodynamic instability','emergency medicine']);
add('em-resus','What is the management of unstable tachycardia?','Synchronized cardioversion (not defibrillation): narrow complex SVT 50-100J, AF 120-200J, VT with pulse 100J — sedate if patient is conscious; do NOT delay for rhythm interpretation if hemodynamically unstable','ACLS: unstable tachycardia = hypotension, altered consciousness, chest pain, or acute pulmonary edema from arrhythmia. Synchronized cardioversion delivers shock during QRS (avoids R-on-T phenomenon). For conscious patients: procedural sedation (ketamine, etomidate, midazolam).',4,'apply',['synchronized cardioversion','unstable tachycardia','ACLS','SVT','AF','emergency medicine']);
add('em-resus','What is return of spontaneous circulation (ROSC) and how is it confirmed?','ROSC: resumption of palpable pulse after cardiac arrest; confirmed by: palpable pulse, ETCO2 spike >40 mmHg, arterial waveform, SpO2 tracing','Clinical signs of ROSC: patient movement, spontaneous breathing, return of pulse. ETCO2 provides real-time confirmation during CPR. After ROSC: post-cardiac arrest bundle (TTM, hemodynamic optimization, 12-lead ECG, coronary angiography if appropriate, neurological assessment).',2,'recall',['ROSC','return of spontaneous circulation','cardiac arrest','ETCO2','emergency medicine']);
add('em-resus','What is the advanced airway approach in pediatric resuscitation?','BVM ventilation with 2-person technique preferred; ETI: uncuffed ET tube (children <8y, size = age/4 + 4), or cuffed tube (age/4 + 3.5) confirmed by ETCO2 and CXR','Pediatric ETI: confirm tube size with broselow tape or formula. Atropine no longer routinely recommended for pediatric RSI. Ketamine + succinylcholine or rocuronium for RSI. Supraglottic airways acceptable if ETI not possible.',3,'apply',['pediatric airway','ETI','pediatric RSI','BVM','emergency medicine']);
add('em-resus','What is the sodium bicarbonate indication in cardiac arrest?','Sodium bicarbonate (1 mEq/kg IV) is indicated for: pre-existing hyperkalemia, sodium channel blocker toxicity (TCA overdose), prolonged arrest with severe metabolic acidosis (pH <7.1) — NOT routine in cardiac arrest','ACLS: routine bicarbonate administration does not improve outcomes in cardiac arrest and may worsen intracellular acidosis. Hyperkalemia-induced arrest: bicarbonate shifts K+ into cells. TCA overdose with wide QRS: 1-2 mEq/kg bicarbonate for QRS >100ms or hemodynamic instability.',3,'apply',['sodium bicarbonate','cardiac arrest','hyperkalemia','TCA overdose','emergency medicine']);
add('em-resus','A 25-year-old is found drowning in an icy lake. He is in cardiac arrest with temperature 28°C. What is different about his resuscitation?','Hypothermic cardiac arrest: CPR, warm IV fluids, active external/internal rewarming; do NOT terminate resuscitation until patient is warm (≥32-35°C) — "No one is dead until they are warm and dead"','ACLS hypothermia guidelines: hypothermic hearts may be in refractory VF until rewarmed — warm first, then attempt defibrillation. ECMO (extracorporeal rewarming) is most effective for severe hypothermia with cardiac arrest. Target rewarming 1-2°C per hour with active techniques.',5,'analyze',['hypothermic cardiac arrest','drowning','rewarming','ECMO','emergency medicine']);
add('em-resus','What is pericardial tamponade and how is it relieved in cardiac arrest?','Tamponade: Beck triad (hypotension, JVD, muffled heart sounds); FAST exam shows pericardial fluid; causes PEA arrest; treat with pericardiocentesis (subxiphoid approach) or surgical thoracotomy in cardiac arrest','Tamponade is a reversible cause of PEA arrest (5Ts). Pericardiocentesis: needle inserted at 45° angle between xiphoid and left costal margin, directed toward left shoulder, aspirate blood. Emergency thoracotomy for traumatic tamponade provides direct access to heart.',4,'apply',['pericardial tamponade','Beck triad','pericardiocentesis','PEA','emergency medicine']);
add('em-resus','What is the role of extracorporeal CPR (ECPR) in cardiac arrest?','ECPR (VA-ECMO during CPR): bridge for refractory cardiac arrest in selected patients (witnessed arrest, <60-65 years, treatable cause, no ROSC after ≥20 min of conventional ACLS)','ECPR provides perfusion while definitive treatment is applied (PCI for MI, warmed for hypothermia, LVAD bridge for cardiomyopathy). SAVE-J and ELSO data show improved survival in selected patients. Limited by availability of ECMO expertise and equipment. CANUCKS/ARREST trials ongoing.',4,'analyze',['ECPR','ECMO cardiac arrest','extracorporeal CPR','refractory arrest','emergency medicine']);
add('em-resus','What are the determinants of successful defibrillation?','Time to defibrillation (most important), biphasic vs. monophasic waveform (biphasic more effective, lower energy), paddle/pad placement (correct position and contact), patient factors (metabolic, drug state)','ACLS: for every minute of VF without defibrillation, survival decreases by 10%. Public access defibrillation (AED) programs in public spaces significantly reduce out-of-hospital cardiac arrest mortality. Biphasic defibrillators (120-200J) are more effective than monophasic (360J) at lower energies.',2,'recall',['defibrillation','AED','biphasic','time to shock','emergency medicine']);

